import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"Generated Settings Pages","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-dev-guide/views/settings_generation.md","filePath":"en/qgc-dev-guide/views/settings_generation.md"}'),n={name:"en/qgc-dev-guide/views/settings_generation.md"};function l(s,e,d,r,c,g){return i(),o("div",null,e[0]||(e[0]=[a('<h1 id="generated-settings-pages" tabindex="-1">Generated Settings Pages <a class="header-anchor" href="#generated-settings-pages" aria-label="Permalink to &quot;Generated Settings Pages&quot;">​</a></h1><p>This page explains how the new Application Settings pages are generated and how to extend them.</p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The runtime stack is:</p><ol><li>Fact metadata in <code>src/Settings/*.SettingsGroup.json</code></li><li>Settings Fact accessors in <code>src/Settings/*Settings.h/.cc</code></li><li>Settings UI page definitions in <code>src/UI/AppSettings/pages/*.SettingsUI.json</code></li><li>Page list in <code>src/UI/AppSettings/pages/SettingsPages.json</code></li><li>Python generator in <code>tools/generators/settings_qml</code></li><li>Generated QML loaded by <code>src/QmlControls/AppSettings.qml</code></li></ol><p>At build time, CMake runs the generator and places generated QML in the build tree. Those files are then compiled into the <code>QGroundControl.AppSettings</code> QML module.</p><h2 id="where-generation-is-wired" tabindex="-1">Where Generation Is Wired <a class="header-anchor" href="#where-generation-is-wired" aria-label="Permalink to &quot;Where Generation Is Wired&quot;">​</a></h2><p>Generation is configured in <a href="../../../../src/UI/AppSettings/CMakeLists.txt">src/UI/AppSettings/CMakeLists.txt</a>:</p><ul><li>Custom command runs: <ul><li><code>python -m tools.generators.settings_qml.generate_pages --output-dir &lt;build&gt;/generated</code></li></ul></li><li>Inputs: <ul><li><code>src/UI/AppSettings/pages/*.json</code></li><li><code>src/Settings/*.SettingsGroup.json</code></li></ul></li><li>Outputs: <ul><li>Generated page QML files (for example <code>AppSettings.qml</code>, <code>FlyViewSettings.qml</code>, ...)</li><li><code>SettingsPagesModel.qml</code></li></ul></li></ul><p>The generator entry point is <a href="./../../../../tools/generators/settings_qml/generate_pages.py.html">tools/generators/settings_qml/generate_pages.py</a>, with most logic in <a href="./../../../../tools/generators/settings_qml/page_generator.py.html">tools/generators/settings_qml/page_generator.py</a>.</p><h2 id="json-files-and-their-roles" tabindex="-1">JSON Files and Their Roles <a class="header-anchor" href="#json-files-and-their-roles" aria-label="Permalink to &quot;JSON Files and Their Roles&quot;">​</a></h2><ol><li><code>SettingsPages.json</code> controls sidebar/page registration:</li></ol><ul><li>Page name</li><li>Icon</li><li>Generated QML file name (<code>qml</code>)</li><li>Source page definition JSON (<code>pageDefinition</code>)</li><li>Optional visibility expression (<code>visible</code>)</li><li>Optional divider entries</li></ul><ol start="2"><li><code>&lt;Page&gt;.SettingsUI.json</code> controls page content:</li></ol><ul><li><code>bindings</code>: reusable QML expressions</li><li><code>groups</code>: section blocks</li><li>Group options: <ul><li><code>heading</code></li><li><code>sectionName</code> (sidebar label override)</li><li><code>showWhen</code>, <code>enableWhen</code></li><li><code>component</code> (embed a custom QML component)</li><li><code>keywords</code> (for search on component-only groups)</li></ul></li><li>Control options: <ul><li><code>setting</code> (required), format: <code>&lt;settingsManager accessor&gt;.&lt;factName&gt;</code></li><li>Optional <code>control</code> override (<code>checkbox</code>, <code>combobox</code>, <code>textfield</code>, <code>slider</code>, <code>browse</code>, <code>scaler</code>)</li><li>Optional <code>label</code>, <code>showWhen</code>, <code>enableWhen</code>, <code>placeholder</code></li><li>Slider-specific <code>enableCheckbox</code> and <code>button</code></li></ul></li></ul><ol start="3"><li><code>*.SettingsGroup.json</code> provides Fact metadata used by both runtime and generation:</li></ol><ul><li>Type</li><li>Label/descriptions</li><li>Enum values</li><li>Visibility/user visibility</li><li>Search <code>keywords</code></li></ul><h2 id="how-controls-are-chosen" tabindex="-1">How Controls Are Chosen <a class="header-anchor" href="#how-controls-are-chosen" aria-label="Permalink to &quot;How Controls Are Chosen&quot;">​</a></h2><p>When <code>control</code> is omitted, the generator auto-selects from Fact metadata:</p><ul><li><code>bool</code> -&gt; checkbox control</li><li>Enum-backed facts -&gt; combobox</li><li>Other types -&gt; text field</li></ul><p>Explicit <code>control</code> in <code>*.SettingsUI.json</code> overrides auto-selection.</p><h2 id="sidebar-sections-and-search" tabindex="-1">Sidebar, Sections, and Search <a class="header-anchor" href="#sidebar-sections-and-search" aria-label="Permalink to &quot;Sidebar, Sections, and Search&quot;">​</a></h2><p>Generated <code>SettingsPagesModel.qml</code> is built from <code>SettingsPages.json</code> and each page definition.</p><p>It includes:</p><ul><li><code>sections</code>: section names for expandable sidebar rows</li><li><code>searchTerms</code>: page/section/fact keyword tokens used by the search field in <a href="./../../../../src/QmlControls/AppSettings.qml.html">src/QmlControls/AppSettings.qml</a></li></ul><p>Search terms are derived from:</p><ul><li>Page name</li><li>Section heading/section name</li><li>Fact metadata <code>keywords</code></li><li>Group-level <code>keywords</code> when using <code>component</code> groups without explicit controls</li></ul><h2 id="add-a-new-setting-to-an-existing-generated-page" tabindex="-1">Add a New Setting to an Existing Generated Page <a class="header-anchor" href="#add-a-new-setting-to-an-existing-generated-page" aria-label="Permalink to &quot;Add a New Setting to an Existing Generated Page&quot;">​</a></h2><ol><li>Add Fact metadata entry to the appropriate <code>src/Settings/&lt;Group&gt;.SettingsGroup.json</code> file.</li><li>Expose that Fact through the corresponding settings class:</li></ol><ul><li>Add <code>DEFINE_SETTINGFACT(&lt;factName&gt;)</code> in the matching <code>*Settings.h</code>.</li><li>Ensure <code>DECLARE_SETTINGSFACT</code> exists in <code>*Settings.cc</code> if required by that file pattern.</li></ul><ol start="3"><li>Add a control entry in the page JSON:</li></ol><ul><li>File: <code>src/UI/AppSettings/pages/&lt;Page&gt;.SettingsUI.json</code></li><li>Add control: <code>{ &quot;setting&quot;: &quot;&lt;accessor&gt;.&lt;factName&gt;&quot; }</code></li></ul><ol start="4"><li>Build QGC. CMake regenerates the QML page automatically.</li></ol><h2 id="add-a-new-generated-settings-page" tabindex="-1">Add a New Generated Settings Page <a class="header-anchor" href="#add-a-new-generated-settings-page" aria-label="Permalink to &quot;Add a New Generated Settings Page&quot;">​</a></h2><ol><li>Create a new page definition JSON in <code>src/UI/AppSettings/pages</code>, for example <code>MyFeature.SettingsUI.json</code>.</li><li>Add a new entry to <code>src/UI/AppSettings/pages/SettingsPages.json</code>:</li></ol><ul><li><code>name</code></li><li><code>icon</code></li><li><code>qml</code> (output file name, for example <code>MyFeatureSettings.qml</code>)</li><li><code>pageDefinition</code> (your new JSON file)</li><li>Optional <code>visible</code> expression</li></ul><ol start="3"><li>Update generated outputs list in <a href="../../../../src/UI/AppSettings/CMakeLists.txt">src/UI/AppSettings/CMakeLists.txt</a>:</li></ol><ul><li>Add your new QML file name to <code>_generated_qml_names</code>.</li></ul><ol start="4"><li>Build QGC to generate and include the new page.</li></ol><h2 id="important-notes-and-gotchas" tabindex="-1">Important Notes and Gotchas <a class="header-anchor" href="#important-notes-and-gotchas" aria-label="Permalink to &quot;Important Notes and Gotchas&quot;">​</a></h2><ul><li>If a page exists in <code>SettingsPages.json</code> but has no <code>pageDefinition</code>, it is not generated; it is treated as hand-written QML/URL content.</li><li>The CMake <code>_generated_qml_names</code> list is explicit. If you forget to add a new page output file name there, generation/build integration will be incomplete.</li><li>The <code>setting</code> path in <code>*.SettingsUI.json</code> must match a valid <code>QGroundControl.settingsManager.&lt;group&gt;.&lt;fact&gt;</code> accessor.</li><li>Fact labels should be present in metadata. Missing labels are logged at runtime by <code>SettingsGroup</code>.</li></ul><h2 id="runtime-override-support" tabindex="-1">Runtime Override Support <a class="header-anchor" href="#runtime-override-support" aria-label="Permalink to &quot;Runtime Override Support&quot;">​</a></h2><p><code>SettingsManager</code> can load external settings override files (from <code>settingsSavePath()</code> with the configured settings file extension), then apply metadata/value/visibility overrides in <code>SettingsManager::adjustSettingMetaData(...)</code>.</p><p>This is separate from page generation, but it affects visibility/defaults in generated UI.</p>',44)]))}const u=t(n,[["render",l]]);export{h as __pageData,u as default};
